```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Begin transaction
  auto begin_result = sqlgen::begin_transaction(conn);
  if (!begin_result) {
    return -1; // Return error if transaction fails
  }

  // Build the delete query with condition
  auto condition = (sqlgen::col("last_login") < "2025-01-01") || 
                   sqlgen::col("last_login").is_null();

  auto delete_query = sqlgen::delete_from<User> | sqlgen::where(condition);

  // Execute the delete operation
  auto delete_result = delete_query(conn);
  if (!delete_result) {
    // Rollback on failure
    auto rollback_result = sqlgen::rollback(conn);
    return rollback_result ? -1 : -2;
  }

  // Commit the transaction
  auto commit_result = sqlgen::commit(conn);
  return commit_result ? 0 : -3;
}

} // namespace delete_inactive_users
```

