#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
    using namespace sqlgen::literals;

    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) return false;

    auto conn = conn_result.value();

    auto begin_result = conn.begin_transaction();
    if (!begin_result) return false;

    auto update_from = sqlgen::update<Account> 
        .set("balance"_c = "balance"_c - amount)
        .where("account_id"_c == from_account_id && "balance"_c >= amount);

    auto update_to = sqlgen::update<Account> 
        .set("balance"_c = "balance"_c + amount)
        .where("account_id"_c == to_account_id);

    auto update_from_result = conn.execute(update_from);
    if (!update_from_result) {
        conn.rollback();
        return false;
    }

    auto update_to_result = conn.execute(update_to);
    if (!update_to_result) {
        conn.rollback();
        return false;
    }

    auto commit_result = conn.commit();
    if (!commit_result) {
        conn.rollback();
        return false;
    }

    return true;
}

}  // namespace transaction_transfer_funds

